interface Config {
  host:     string;        // required
  port?:    number;        // optional → number | undefined
  timeout?: number;        // optional → number | undefined
  debug?:   boolean;
}

// All of these are valid
const a: Config = { host: "localhost" };
const b: Config = { host: "localhost", port: 3000 };
const c: Config = { host: "localhost", port: undefined }; // explicit undefined is OK

// Accessing an optional property safely
function connect(cfg: Config): void {
  const port    = cfg.port    ?? 3000;    // nullish coalescing
  const timeout = cfg.timeout ?? 5000;
  console.log(`Connecting to ${cfg.host}:${port} (timeout ${timeout}ms)`);
}

// TypeScript forces you to handle the undefined case
function logPort(cfg: Config): void {
  // cfg.port.toFixed(0);       // Error: cfg.port is possibly undefined
  cfg.port?.toFixed(0);         // OK — optional chaining
  if (cfg.port !== undefined) {
    cfg.port.toFixed(0);        // OK — narrowed to number
  }
}

// Function parameters: optional must trail required
function greet(name: string, greeting?: string): string {
  return `${greeting ?? "Hello"}, ${name}!`;
}
// greet("Alice");           // "Hello, Alice!"
// greet("Bob", "Hi");      // "Hi, Bob!"

// Interface properties: any order, no constraint
interface Notification {
  id:       number;
  message?: string;  // optional can come before required
  severity: "info" | "warn" | "error";
  timestamp?: Date;
}

// Destructuring with defaults — cleans up optional access
function showNotification({ message = "No message", severity }: Notification): void {
  console.log(`[${severity}] ${message}`);
}

interface Point {
  readonly x: number;
  readonly y: number;
}

const origin: Point = { x: 0, y: 0 };
// origin.x = 1; // Error: Cannot assign to 'x' because it is a read-only property

// Spread to create a modified copy — this is the correct pattern
const shifted: Point = { ...origin, x: 5 };
console.log(shifted); // { x: 5, y: 0 }

// readonly in a class
class ImmutableRange {
  readonly start: number;
  readonly end: number;

  constructor(start: number, end: number) {
    this.start = start; // OK in constructor
    this.end   = end;
  }

  // extend(): ImmutableRange {
  //   this.end += 10; // Error — readonly
  //   return this;
  // }

  extend(by: number): ImmutableRange {
    return new ImmutableRange(this.start, this.end + by); // return new instance
  }
}

// readonly arrays — elements cannot be mutated
interface Config {
  readonly allowedOrigins: readonly string[];
}

const cfg: Config = { allowedOrigins: ["https://example.com"] };
// cfg.allowedOrigins.push("http://evil.com"); // Error — readonly array

interface UserProfile {
  readonly id:       number;       // required, immutable
  name:              string;       // required, mutable
  readonly createdAt: Date;        // required, immutable
  bio?:              string;       // optional, mutable
  readonly avatarUrl?: string;     // optional, immutable
}

// Create — all required fields must be present
const user: UserProfile = {
  id:        1,
  name:      "Alice",
  createdAt: new Date(),
  // bio and avatarUrl omitted — both optional
};

// Update — use Partial + Omit to create a safe update type
type UpdateProfile = Partial<Omit<UserProfile, "id" | "createdAt">>;
// { name?: string; bio?: string; avatarUrl?: string }
// id and createdAt are excluded — they must not change after creation

function applyUpdate(profile: UserProfile, update: UpdateProfile): UserProfile {
  return { ...profile, ...update };
}

interface User {
  id:    number;
  name:  string;
  email: string;
}

// Partial<T> — every property becomes optional
type PartialUser = Partial<User>;
// { id?: number; name?: string; email?: string }

// Required<T> — every property becomes required (removes ?)
interface Config { host?: string; port?: number }
type FullConfig = Required<Config>;
// { host: string; port: number }

// Readonly<T> — every property becomes readonly
type FrozenUser = Readonly<User>;
// { readonly id: number; readonly name: string; readonly email: string }

// Mutable<T> — remove readonly (not in std lib, define it yourself)
type Mutable<T> = { -readonly [K in keyof T]: T[K] };
type MutableUser = Mutable<FrozenUser>;
// { id: number; name: string; email: string } — writable again

// Remove optional modifiers — also a custom mapped type
type NonPartial<T> = { [K in keyof T]-?: T[K] };
// Same effect as Required<T>

// Combine: read-only with some optional properties
type EditableUser = Readonly<Partial<Pick<User, "name" | "email">>>;
// { readonly name?: string; readonly email?: string }

import { Component, input, InputSignal } from "@angular/core";

interface CardInputs {
  title:       string;             // required
  subtitle?:   string;             // optional
  imageUrl?:   string;             // optional
  variant?:    "default" | "compact" | "wide";
}

@Component({
  selector:  "app-card",
  template:  `
    <div [class]="variant()">
      <img *ngIf="imageUrl()" [src]="imageUrl()">
      <h2>{{ title() }}</h2>
      <p *ngIf="subtitle()">{{ subtitle() }}</p>
    </div>
  `,
})
class CardComponent {
  title:    InputSignal<string>                        = input.required();
  subtitle: InputSignal<string | undefined>            = input<string>();
  imageUrl: InputSignal<string | undefined>            = input<string>();
  variant:  InputSignal<"default"|"compact"|"wide">   = input<"default"|"compact"|"wide">("default");
}

// Readonly signal reference — reassigning the signal itself is a compile error
// Assigning the *value* of the signal is also blocked because inputs are read-only

import { signal, computed } from "@angular/core";

interface AppState {
  readonly user:   Readonly<User> | null;
  readonly cart:   readonly CartItem[];
  readonly config: Readonly<Config>;
}

// State is a readonly snapshot — nothing inside can be accidentally mutated
const state = signal<AppState>({
  user:   null,
  cart:   [],
  config: { host: "api.example.com", port: 443 },
});

// Derive computed values — also readonly
const cartCount = computed(() => state().cart.length);
const hasUser   = computed(() => state().user !== null);

// To update: replace the whole slice (immutable update pattern)
function addToCart(item: CartItem): void {
  state.update(s => ({
    ...s,
    cart: [...s.cart, item],   // new array — not mutating the readonly one
  }));
}

// Attempting to mutate directly would be a TS error:
// state().cart.push(item);    // Error — readonly array
// state().user!.name = "Eve"; // Error — Readonly<User>

import { HttpClient } from "@angular/common/http";

// Server responses should be readonly — we should not mutate them
interface ApiUser {
  readonly id:        number;
  readonly name:      string;
  readonly email:     string;
  readonly createdAt: string;
}

// Request bodies: required fields only, no id/timestamps (server sets those)
interface CreateUserRequest {
  name:  string;
  email: string;
  // password is required on creation only — not returned by the API
  password: string;
}

interface UpdateUserRequest {
  name?:  string;   // all fields optional — send only what changed
  email?: string;
}

@Injectable({ providedIn: "root" })
class UserApiService {
  constructor(private http: HttpClient) {}

  getUser(id: number) {
    return this.http.get<Readonly<ApiUser>>(`/api/users/${id}`);
  }

  createUser(body: CreateUserRequest) {
    return this.http.post<ApiUser>("/api/users", body);
  }

  updateUser(id: number, body: UpdateUserRequest) {
    return this.http.patch<ApiUser>(`/api/users/${id}`, body);
  }
}

// Shallow — nested mutation still allowed at type level
type ShallowPoint = Readonly<{ coords: { x: number; y: number } }>;
const sp: ShallowPoint = { coords: { x: 1, y: 2 } };
// sp.coords = { x: 0, y: 0 }; // Error — top-level is readonly
sp.coords.x = 99; // OK! — nested object is NOT readonly

// Deep readonly — recursive mapped type
type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];
};

type DeepPoint = DeepReadonly<{ coords: { x: number; y: number } }>;
const dp: DeepPoint = { coords: { x: 1, y: 2 } };
// dp.coords.x = 99; // Error — nested is readonly too

// Practical Angular: immutable API response
interface OrderDetail {
  id:       number;
  items:    { productId: number; quantity: number }[];
  shipping: { address: string; method: string };
}

type ImmutableOrder = DeepReadonly<OrderDetail>;
// Every nested field — items[n].quantity, shipping.address — is readonly

// Optional: property may be ABSENT (not present on the object)
interface A {
  name?: string; // name: string | undefined
}
const a1: A = {};           // OK — name is absent
const a2: A = { name: undefined }; // OK — explicitly undefined
const a3: A = { name: "Alice" };   // OK — has a value

// Nullable: property MUST be present, but can be null
interface B {
  name: string | null;
}
// const b1: B = {}; // Error — name is required
const b2: B = { name: null };   // OK — explicitly null
const b3: B = { name: "Bob" };  // OK

// JSON APIs typically use null (not undefined) for absent values
// because JSON.stringify() omits undefined properties
interface ApiUser {
  id:       number;
  avatar:   string | null;  // null means "no avatar" — always present in JSON
  bio?:     string;         // may be omitted from the response entirely
}

// When to use which:
// ? — optional: value is not needed and may simply not be sent
// | null — nullable: value is always sent but can explicitly be "nothing"
// strictNullChecks must be enabled for both to work correctly

// Default behavior: name?: string means name: string | undefined
// You can explicitly assign undefined to an optional property:
interface Config {
  timeout?: number;
}
const c: Config = { timeout: undefined }; // allowed by default

// With "exactOptionalPropertyTypes": true in tsconfig.json:
// optional means ABSENT — you cannot explicitly assign undefined:
// const c: Config = { timeout: undefined }; // Error — value undefined is not assignable
// Only allowed: const c: Config = {}; or const c: Config = { timeout: 3000 };

// tsconfig.json:
// {
//   "compilerOptions": {
//     "exactOptionalPropertyTypes": true,
//     "strictNullChecks": true
//   }
// }

// This catches a subtle class of bugs where undefined is explicitly set
// but the consumer is not checking for undefined correctly

// Readonly array — prevents all mutating methods
const colors: readonly string[] = ["red", "green", "blue"];
// colors.push("yellow"); // Error
// colors[0] = "purple";  // Error
const more = [...colors, "yellow"]; // OK — spread creates a new array

// Readonly<T[]> is equivalent to readonly T[]
type ReadonlyColors = Readonly<string[]>; // same as readonly string[]

// Readonly tuple — fixed-length, immutable
type RGB = readonly [number, number, number];
const red: RGB = [255, 0, 0];
// red[0] = 200; // Error — readonly tuple

// Angular signals return readonly arrays to prevent external mutation
import { signal } from "@angular/core";

const items = signal<readonly string[]>([]);

// Adding an item: always replace the whole array
function addItem(label: string): void {
  items.update(curr => [...curr, label]);
}

// Reading safely — no mutation possible on the returned value
const first = items()[0]; // string | undefined

interface Entity {
  readonly id:        number;
  readonly createdAt: Date;
}

class Order implements Entity {
  readonly id:        number;
  readonly createdAt: Date;
  status:             "pending" | "shipped" | "delivered";

  constructor(id: number) {
    this.id        = id;
    this.createdAt = new Date(); // OK — assignment in constructor
    this.status    = "pending";
  }

  ship(): Order {
    // this.id = 99;     // Error — readonly
    return Object.assign(Object.create(Object.getPrototypeOf(this)), {
      ...this,
      status: "shipped",
    });
  }
}

// readonly + private pattern — maximum protection
class Config {
  constructor(
    private readonly host: string,
    private readonly port: number
  ) {}

  getUrl(): string {
    return `${this.host}:${this.port}`;
  }
}

// Angular: readonly injected services prevent re-assignment
@Injectable({ providedIn: "root" })
class UserService {
  constructor(private readonly http: HttpClient) {}
  // this.http = something; // Error — readonly
}

interface Opts {
  color?: string;
  size?:  number;
}

// Object literal — excess property check active
// const o: Opts = { colour: "red" }; // Error: 'colour' does not exist (typo)

// Variable assignment — excess check NOT applied
const raw = { colour: "red" };
const o: Opts = raw; // No error — raw satisfies Opts structurally

// This asymmetry helps catch typos in config objects:
function createButton(opts: Opts = {}) {
  const color = opts.color ?? "blue";
  const size  = opts.size  ?? 16;
  return { color, size };
}

// createButton({ colour: "red" }); // Error — caught at the call site
// createButton({ color: "red" });  // OK

// Use `satisfies` (TS 4.9) to validate without losing the literal type
const buttonOpts = {
  color: "red",
  size:  14,
} satisfies Opts; // validates against Opts; preserves literal types
// buttonOpts.color: "red" (literal), not string
